// Lambda auth handler (simplified)
exports.handler = async (event) => {
  const { email, password } = JSON.parse(event.body);

  // Validate against DynamoDB
  const user = await dynamodb.get({
    TableName: 'syncdocs-users',
    Key: { email }
  }).promise();

  if (!user.Item || !bcrypt.compareSync(password, user.Item.passwordHash)) {
    return { statusCode: 401, body: 'Unauthorized' };
  }

  // Issue JWT
  const token = jwt.sign(
    { userId: user.Item.id, email },
    process.env.JWT_SECRET,
    { expiresIn: '24h' }
  );

  return { statusCode: 200, body: JSON.stringify({ token }) };
};

// Delta op handler (simplified)
wss.on('connection', (ws, req) => {
  const { docId, userId } = parseAuth(req);

  ws.on('message', async (data) => {
    const delta = JSON.parse(data);

    // Publish delta op to Kafka
    await producer.send({
      topic: 'doc.delta.ops',
      messages: [{
        key: docId,
        value: JSON.stringify({
          docId,
          userId,
          delta,
          timestamp: Date.now()
        })
      }]
    });

    // Broadcast to other clients on same doc
    broadcastToDoc(docId, userId, delta);
  });
});

// IO Processor вҖ” OT-based delta application (simplified)
consumer.run({
  eachMessage: async ({ message }) => {
    const { docId, userId, delta } = JSON.parse(message.value);

    // Load current document state from EFS
    const docPath = `/efs/docs/${docId}.json`;
    const current = await fs.readFile(docPath, 'utf8');
    const doc = JSON.parse(current);

    // Apply Operational Transformation
    const transformed = ot.transform(delta, doc.pendingOps);
    const newState = ot.apply(doc.content, transformed);

    // Persist updated state
    await fs.writeFile(docPath, JSON.stringify({
      content: newState,
      version: doc.version + 1,
      lastModified: Date.now()
    }));
  }
});
